# block_rq_issue에서 타임스탬프 저장, block_rq_complete에서 지연 측정
bpftrace -e '
  tracepoint:block:___ {
    @start[args->dev, args->sector] = nsecs;
  }
  tracepoint:block:___ /@start[args->dev, args->sector]/ {
    @usecs = hist((nsecs - @start[args->dev, args->sector]) / 1000);
    delete(@start[args->dev, args->sector]);
  }
'
